-- =============================================================
-- FILE: 131_bereketfide_storage_assets.seed.sql
-- Bereket Fide — Local Storage Assets (uploads/)
-- =============================================================

SET NAMES utf8mb4;
SET time_zone = '+00:00';
SET FOREIGN_KEY_CHECKS = 0;

START TRANSACTION;

-- =========================
-- PRODUCT IMAGES
-- =========================
ON DUPLICATE KEY UPDATE
  url = VALUES(url),
  size = VALUES(size),
  updated_at = NOW();

-- =========================
-- NEWS IMAGES
-- =========================
ON DUPLICATE KEY UPDATE
  url = VALUES(url),
  size = VALUES(size),
  updated_at = NOW();

-- =========================
-- BRAND REFERENCES (is birligi firma logolari)
-- =========================
ON DUPLICATE KEY UPDATE
  url = VALUES(url),
  size = VALUES(size),
  width = VALUES(width),
  height = VALUES(height),
  updated_at = NOW();

-- =========================
-- INVENTORY SEED PACKAGE IMAGES
-- =========================
ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  size = VALUES(size),
  width = VALUES(width),
  height = VALUES(height),
  url = VALUES(url),
  metadata = VALUES(metadata),
  updated_at = NOW();

COMMIT;
SET FOREIGN_KEY_CHECKS = 1;
